"use client"

import React, { useEffect, useState } from "react"
import { useSearchParams } from "next/navigation"
import { motion } from "framer-motion"
import Lottie from "lottie-react"
import ExplorePostsFilter, { FilterState } from "@/components/posts/ExplorePostsFilter"
import NoPostsHolder from "@/components/posts/NoPostsHolder"
import PostCard from "@/components/posts/PostCard"
import { mockPosts } from "./mockPosts"
import explorerAnimation from "@/assets/animations/explorer-walking.json"

export default function ExplorePostsPage() {
  const searchParams = useSearchParams()
  const initialTag = searchParams.get("tag") || ""

  const [filters, setFilters] = useState<FilterState>({
    keyword: "",
    tag: initialTag,
    dateRange: "all",
    sort: "recent",
  })

  const [filteredPosts, setFilteredPosts] = useState(mockPosts)
  const [animationFinished, setAnimationFinished] = useState(false)

  useEffect(() => {
    let results = mockPosts

    if (filters.keyword) {
      results = results.filter((post) =>
        post.title.toLowerCase().includes(filters.keyword.toLowerCase()) ||
        post.description.toLowerCase().includes(filters.keyword.toLowerCase())
      )
    }

    if (filters.tag) {
      results = results.filter((post) => post.tags?.includes(filters.tag))
    }

    setFilteredPosts(results)
  }, [filters])

  return (
    <main className="bg-slate-900 text-white min-h-screen pt-8 pb-16 overflow-hidden">
      <section className="max-w-7xl mx-auto px-4 md:px-8">
        {/* Animated Header */}
        <div className="relative mb-12 h-28 flex items-center overflow-hidden">
          {/* Lottie animation walking from left to right */}
          <motion.div
            initial={{ x: -100, opacity: 0 }}
            animate={{ x: "100%", opacity: 1 }}
            transition={{ duration: 4, ease: "easeInOut" }}
            className="absolute left-0 top-0 w-20 h-20"
            onAnimationComplete={() => setAnimationFinished(true)}
          >
            <Lottie animationData={explorerAnimation} loop={false} />
          </motion.div>

          {/* Title and description revealed progressively */}
          <div className="w-full flex justify-between items-end">
            <motion.h1
              className="text-3xl md:text-4xl font-bold"
              initial={{ opacity: 0 }}
              animate={animationFinished ? { opacity: 1 } : {}}
              transition={{ delay: 0.2, duration: 0.6 }}
            >
              🕵️ Explore Posts
            </motion.h1>
            <motion.p
              className="text-slate-400 text-sm md:text-base max-w-xl text-right"
              initial={{ opacity: 0 }}
              animate={animationFinished ? { opacity: 1 } : {}}
              transition={{ delay: 0.6, duration: 0.6 }}
            >
              Search and filter through various posts.
            </motion.p>
          </div>
        </div>

        {/* Filters */}
        <ExplorePostsFilter filters={filters} setFilters={setFilters} />

        {/* Posts or Empty State */}
        {filteredPosts.length > 0 ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 mt-6">
            {filteredPosts.map((post) => (
              <PostCard key={post.id} {...post} onClick={() => {}} />
            ))}
          </div>
        ) : (
          <div className="mt-10">
            <NoPostsHolder />
          </div>
        )}
      </section>
    </main>
  )
}